### Go Module Design

```go
package caut

import (
    "context"
    "encoding/json"
    "os/exec"
    "time"
)

// Client interfaces with caut CLI
type Client struct {
    CautPath string        // Path to caut binary (default: "caut")
    Timeout  time.Duration // Command timeout (default: 30s)
}

// NewClient creates a caut client with defaults
func NewClient() *Client {
    return &Client{
        CautPath: "caut",
        Timeout:  30 * time.Second,
    }
}

// IsAvailable checks if caut is installed
func (c *Client) IsAvailable() bool {
    _, err := exec.LookPath(c.CautPath)
    return err == nil
}

// FetchUsage queries caut for provider usage
func (c *Client) FetchUsage(ctx context.Context, providers []string) (*UsageResult, error) {
    args := []string{"usage", "--format", "json"}
    for _, p := range providers {
        args = append(args, "--provider", p)
    }

    ctx, cancel := context.WithTimeout(ctx, c.Timeout)
    defer cancel()

    cmd := exec.CommandContext(ctx, c.CautPath, args...)
    output, err := cmd.Output()
    if err != nil {
        return nil, fmt.Errorf("caut failed: %w", err)
    }

    var result CautResponse
    if err := json.Unmarshal(output, &result); err != nil {
        return nil, fmt.Errorf("parse caut output: %w", err)
    }

    return &UsageResult{
        SchemaVersion: result.SchemaVersion,
        Payloads:      result.Data.Payloads,
        Errors:        result.Errors,
        FetchedAt:     time.Now(),
    }, nil
}

// GetProviderUsage fetches usage for a single provider
func (c *Client) GetProviderUsage(ctx context.Context, provider string) (*ProviderPayload, error) {
    result, err := c.FetchUsage(ctx, []string{provider})
    if err != nil {
        return nil, err
    }
    if len(result.Payloads) == 0 {
        return nil, fmt.Errorf("no data for provider %s", provider)
    }
    return &result.Payloads[0], nil
}

// AgentTypeToProvider maps NTM agent type to caut provider
func AgentTypeToProvider(agentType string) string {
    switch agentType {
    case "cc":
        return "claude"
    case "cod":
        return "codex"
    case "gmi":
        return "gemini"
    default:
        return ""
    }
}
```

### Data Structures (Matching caut Output)

```go
package caut

import "time"

// CautResponse is the top-level caut JSON structure
type CautResponse struct {
    SchemaVersion string   `json:"schema_version"` // "caut.v1"
    Command       string   `json:"command"`        // "usage"
    Timestamp     string   `json:"timestamp"`
    Data          CautData `json:"data"`
    Errors        []string `json:"errors"`
}

type CautData struct {
    Payloads []ProviderPayload `json:"payloads"`
}

// ProviderPayload contains usage data for one provider
type ProviderPayload struct {
    Provider string        `json:"provider"`
    Account  *string       `json:"account,omitempty"`
    Source   string        `json:"source"` // "web", "cli", "api"
    Status   *StatusInfo   `json:"status,omitempty"`
    Usage    UsageSnapshot `json:"usage"`
}

// UsageSnapshot contains rate window information
type UsageSnapshot struct {
    PrimaryRateWindow   *RateWindow `json:"primary_rate_window,omitempty"`
    SecondaryRateWindow *RateWindow `json:"secondary_rate_window,omitempty"`
    TertiaryRateWindow  *RateWindow `json:"tertiary_rate_window,omitempty"`
    Identity            *Identity   `json:"identity,omitempty"`
}

// RateWindow describes a usage rate limiting window
type RateWindow struct {
    UsedPercent      *float64   `json:"used_percent,omitempty"`
    WindowMinutes    *int       `json:"window_minutes,omitempty"`
    ResetsAt         *time.Time `json:"resets_at,omitempty"`
    ResetDescription *string    `json:"reset_description,omitempty"`
}

// Identity contains account information
type Identity struct {
    AccountEmail *string `json:"account_email,omitempty"`
    PlanName     *string `json:"plan_name,omitempty"`
}

// UsageResult is the processed result for NTM consumption
type UsageResult struct {
    SchemaVersion string
    Payloads      []ProviderPayload
    Errors        []string
    FetchedAt     time.Time
}

// Helper methods

// IsRateLimited returns true if primary window usage > threshold
func (p *ProviderPayload) IsRateLimited(threshold float64) bool {
    if p.Usage.PrimaryRateWindow == nil || p.Usage.PrimaryRateWindow.UsedPercent == nil {
        return false
    }
    return *p.Usage.PrimaryRateWindow.UsedPercent >= threshold
}

// GetResetTime returns when the primary window resets
func (p *ProviderPayload) GetResetTime() *time.Time {
    if p.Usage.PrimaryRateWindow == nil {
        return nil
    }
    return p.Usage.PrimaryRateWindow.ResetsAt
}

// UsedPercent returns primary window usage percentage
func (p *ProviderPayload) UsedPercent() *float64 {
    if p.Usage.PrimaryRateWindow == nil {
        return nil
    }
    return p.Usage.PrimaryRateWindow.UsedPercent
}
